#include <stdio.h>
#include <stdlib.h>
#include <float.h>
#include <math.h>
#include "kmeans.h"

#ifndef FLT_MAX
#define FLT_MAX 3.40282347e+38
#endif

extern int num_omp_threads;

__global__ void find_nearest_point_kernel(float *pt,
                                          int nfeatures,
                                          float *pts,
                                          int npts,
                                          int nclusters,
                                          int *index,
                                          float *min_dist)
{
    int i = 0;
    float local_min_dist = FLT_MAX;
    int local_index = 0;

    for (i = 0; i < npts; i++) {
        float dist = 0.0f;
        for (int d = 0; d < nfeatures; d++) {
            float diff = pt[d] - pts[i * nfeatures + d];
            dist += diff * diff;
        }
        if (dist < local_min_dist) {
            local_min_dist = dist;
            local_index = i;
        }
    }

    if (local_min_dist < min_dist[0]) {
        min_dist[0] = local_min_dist;
        index[0] = local_index;
    }
}

__inline
float euclid_dist_2(float *pt1,
                    float *pt2,
                    int    numdims)
{
    int i;
    float ans = 0.0f;

    for (i = 0; i < numdims; i++)
        ans += (pt1[i] - pt2[i]) * (pt1[i] - pt2[i]);

    return(ans);
}

int find_nearest_point(float  *pt,
                       int     nfeatures,
                       float **pts,
                       int     npts)
{
    int index, i;
    float min_dist = FLT_MAX;

    for (i = 0; i < npts; i++) {
        float dist;
        dist = euclid_dist_2(pt, pts[i], nfeatures);
        if (dist < min_dist) {
            min_dist = dist;
            index    = i;
        }
    }
    return(index);
}

__global__ void assign_clusters_kernel(float *feature,
                                       float *clusters,
                                       int *membership,
                                       int *partial_new_centers_len,
                                       float *partial_new_centers,
                                       int npoints,
                                       int nclusters,
                                       int nfeatures,
                                       int nthreads,
                                       float *delta)
{
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    int tid = blockIdx.y;

    if (i >= npoints) return;

    float *pt = feature + i * nfeatures;
    float min_dist = FLT_MAX;
    int index = 0;

    for (int c = 0; c < nclusters; c++) {
        float dist = 0.0f;
        for (int d = 0; d < nfeatures; d++) {
            float diff = pt[d] - clusters[c * nfeatures + d];
            dist += diff * diff;
        }
        if (dist < min_dist) {
            min_dist = dist;
            index = c;
        }
    }

    if (membership[i] != index) {
        delta[0] += 1.0f;
    }

    membership[i] = index;

    partial_new_centers_len[tid * nclusters + index]++;

    for (int j = 0; j < nfeatures; j++) {
        partial_new_centers[tid * nclusters * nfeatures + index * nfeatures + j] += feature[i * nfeatures + j];
    }
}

float** kmeans_clustering(float **feature,
                          int     nfeatures,
                          int     npoints,
                          int     nclusters,
                          float   threshold,
                          int    *membership)
{
    int      i, j, k, n = 0, index, loop = 0;
    int     *new_centers_len;
    float  **new_centers;
    float  **clusters;
    float    delta;
    double   timing;

    int      nthreads;
    int    **partial_new_centers_len;
    float ***partial_new_centers;

    nthreads = num_omp_threads;

    clusters    = (float**) malloc(nclusters * sizeof(float*));
    clusters[0] = (float*)  malloc(nclusters * nfeatures * sizeof(float));
    for (i = 1; i < nclusters; i++)
        clusters[i] = clusters[i - 1] + nfeatures;

    for (i = 0; i < nclusters; i++) {
        for (j = 0; j < nfeatures; j++)
            clusters[i][j] = feature[n][j];
        n++;
    }

    for (i = 0; i < npoints; i++)
        membership[i] = -1;

    new_centers_len = (int*) calloc(nclusters, sizeof(int));

    new_centers    = (float**) malloc(nclusters * sizeof(float*));
    new_centers[0] = (float*)  calloc(nclusters * nfeatures, sizeof(float));
    for (i = 1; i < nclusters; i++)
        new_centers[i] = new_centers[i - 1] + nfeatures;

    partial_new_centers_len    = (int**) malloc(nthreads * sizeof(int*));
    partial_new_centers_len[0] = (int*)  calloc(nthreads * nclusters, sizeof(int));
    for (i = 1; i < nthreads; i++)
        partial_new_centers_len[i] = partial_new_centers_len[i - 1] + nclusters;

    partial_new_centers    = (float**)malloc(nthreads * sizeof(float*));
    partial_new_centers[0] = (float*) malloc(nthreads * nclusters * nfeatures * sizeof(float));
    for (i = 1; i < nthreads; i++)
        partial_new_centers[i] = partial_new_centers[i - 1] + nclusters * nfeatures;

    for (i = 0; i < nthreads; i++) {
        for (j = 0; j < nclusters; j++)
            for (k = 0; k < nfeatures; k++)
                partial_new_centers[i][j * nfeatures + k] = 0.0f;
    }

    printf("num of threads = %d\n", num_omp_threads);

    float *d_feature, *d_clusters, *d_partial_new_centers;
    int *d_membership, *d_partial_new_centers_len;
    float *d_delta;

    cudaMalloc(&d_feature, npoints * nfeatures * sizeof(float));
    cudaMalloc(&d_clusters, nclusters * nfeatures * sizeof(float));
    cudaMalloc(&d_membership, npoints * sizeof(int));
    cudaMalloc(&d_partial_new_centers, nthreads * nclusters * nfeatures * sizeof(float));
    cudaMalloc(&d_partial_new_centers_len, nthreads * nclusters * sizeof(int));
    cudaMalloc(&d_delta, sizeof(float));

    cudaMemcpy(d_feature, feature[0], npoints * nfeatures * sizeof(float), cudaMemcpyHostToDevice);
    cudaMemcpy(d_clusters, clusters[0], nclusters * nfeatures * sizeof(float), cudaMemcpyHostToDevice);
    cudaMemcpy(d_membership, membership, npoints * sizeof(int), cudaMemcpyHostToDevice);

    do {
        delta = 0.0f;
        cudaMemset(d_delta, 0, sizeof(float));
        cudaMemset(d_partial_new_centers_len, 0, nthreads * nclusters * sizeof(int));
        cudaMemset(d_partial_new_centers, 0, nthreads * nclusters * nfeatures * sizeof(float));

        dim3 blockDim(256);
        dim3 numBlocks((npoints + blockDim.x - 1) / blockDim.x, nthreads);

        assign_clusters_kernel<<<numBlocks, blockDim>>>(d_feature,
                                                        d_clusters,
                                                        d_membership,
                                                        d_partial_new_centers_len,
                                                        d_partial_new_centers,
                                                        npoints,
                                                        nclusters,
                                                        nfeatures,
                                                        nthreads,
                                                        d_delta);

        cudaMemcpy(delta, d_delta, sizeof(float), cudaMemcpyDeviceToHost);

        cudaMemcpy(d_partial_new_centers_len, d_partial_new_centers_len, nthreads * nclusters * sizeof(int), cudaMemcpyDeviceToHost);
        cudaMemcpy(d_partial_new_centers, d_partial_new_centers, nthreads * nclusters * nfeatures * sizeof(float), cudaMemcpyDeviceToHost);

        int *host_partial_len = (int*)malloc(nthreads * nclusters * sizeof(int));
        float *host_partial_centers = (float*)malloc(nthreads * nclusters * nfeatures * sizeof(float));
        cudaMemcpy(host_partial_len, d_partial_new_centers_len, nthreads * nclusters * sizeof(int), cudaMemcpyDeviceToHost);
        cudaMemcpy(host_partial_centers, d_partial_new_centers, nthreads * nclusters * nfeatures * sizeof(float), cudaMemcpyDeviceToHost);

        for (i = 0; i < nclusters; i++) {
            for (j = 0; j < nthreads; j++) {
                new_centers_len[i] += host_partial_len[j * nclusters + i];
                host_partial_len[j * nclusters + i] = 0;
                for (k = 0; k < nfeatures; k++) {
                    new_centers[0][i * nfeatures + k] += host_partial_centers[j * nclusters * nfeatures + i * nfeatures + k];
                    host_partial_centers[j * nclusters * nfeatures + i * nfeatures + k] = 0.0f;
                }
            }
        }

        for (i = 0; i < nclusters; i++) {
            for (j = 0; j < nfeatures; j++) {
                if (new_centers_len[i] > 0)
                    clusters[i][j] = new_centers[0][i * nfeatures + j] / new_centers_len[i];
                new_centers[0][i * nfeatures + j] = 0.0f;
            }
            new_centers_len[i] = 0;
        }

        cudaMemcpy(d_clusters, clusters[0], nclusters * nfeatures * sizeof(float), cudaMemcpyHostToDevice);

        free(host_partial_len);
        free(host_partial_centers);

    } while (delta > threshold && loop++ < 500);

    cudaFree(d_feature);
    cudaFree(d_clusters);
    cudaFree(d_membership);
    cudaFree(d_partial_new_centers);
    cudaFree(d_partial_new_centers_len);
    cudaFree(d_delta);

    free(new_centers[0]);
    free(new_centers);
    free(new_centers_len);

    for (i = 0; i < nthreads; i++)
        free(partial_new_centers[i]);
    free(partial_new_centers);
    free(partial_new_centers_len[0]);
    free(partial_new_centers_len);

    return clusters;
}

