#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <limits.h>
#include <math.h>
#include <sys/types.h>
#include <fcntl.h>
#include "getopt.h"

#include "kmeans.h"

int num_omp_threads = 1;

void usage(char *argv0) {
    char *help =
        "Usage: %s [switches] -i filename\n"
        "       -i filename     		: file containing data to be clustered\n"
        "       -b                 	: input file is in binary format\n"
        "       -k                 	: number of clusters (default is 5) \n"
        "       -t threshold		: threshold value\n"
        "       -n no. of threads	: number of threads";
    fprintf(stderr, help, argv0);
    exit(-1);
}

int cluster(int      numObjects,
            int      numAttributes,
            float  **attributes,
            int      nclusters,
            float    threshold,
            float ***cluster_centres)
{
    int    *membership;
    float **tmp_cluster_centres;

    membership = (int*) malloc(numObjects * sizeof(int));

    srand(7);

    tmp_cluster_centres = kmeans_clustering(attributes,
                                            numAttributes,
                                            numObjects,
                                            nclusters,
                                            threshold,
                                            membership);

    if (*cluster_centres) {
        free((*cluster_centres)[0]);
        free(*cluster_centres);
    }
    *cluster_centres = tmp_cluster_centres;

    free(membership);

    return 0;
}

int main(int argc, char **argv) {
    int     opt;
    extern char   *optarg;
    extern int     optind;
    int     nclusters = 5;
    char   *filename = 0;
    float  *buf;
    float **attributes;
    float **cluster_centres = NULL;
    int     i, j;

    int     numAttributes;
    int     numObjects;
    char    line[1024];
    int     isBinaryFile = 0;
    int     nloops = 1;
    float   threshold = 0.001;
    double  timing;

    while ((opt = getopt(argc, argv, "i:k:t:b:n:?")) != EOF) {
        switch (opt) {
        case 'i': filename = optarg;
            break;
        case 'b': isBinaryFile = 1;
            break;
        case 't': threshold = atof(optarg);
            break;
        case 'k': nclusters = atoi(optarg);
            break;
        case 'n': num_omp_threads = atoi(optarg);
            break;
        case '?': usage(argv[0]);
            break;
        default: usage(argv[0]);
            break;
        }
    }

    if (filename == 0) usage(argv[0]);

    numAttributes = numObjects = 0;

    if (isBinaryFile) {
        int infile;
        if ((infile = open(filename, O_RDONLY, "0600")) == -1) {
            fprintf(stderr, "Error: no such file (%s)\n", filename);
            exit(1);
        }
        read(infile, &numObjects, sizeof(int));
        read(infile, &numAttributes, sizeof(int));

        buf           = (float*) malloc(numObjects * numAttributes * sizeof(float));
        attributes    = (float**)malloc(numObjects * sizeof(float*));
        attributes[0] = (float*) malloc(numObjects * numAttributes * sizeof(float));
        for (i = 1; i < numObjects; i++)
            attributes[i] = attributes[i - 1] + numAttributes;

        read(infile, buf, numObjects * numAttributes * sizeof(float));

        close(infile);
    }
    else {
        FILE *infile;
        if ((infile = fopen(filename, "r")) == NULL) {
            fprintf(stderr, "Error: no such file (%s)\n", filename);
            exit(1);
        }
        while (fgets(line, 1024, infile) != NULL)
            if (strtok(line, " \t\n") != 0)
                numObjects++;
        rewind(infile);
        while (fgets(line, 1024, infile) != NULL) {
            if (strtok(line, " \t\n") != 0) {
                while (strtok(NULL, " ,\t\n") != NULL) numAttributes++;
                break;
            }
        }

        buf           = (float*) malloc(numObjects * numAttributes * sizeof(float));
        attributes    = (float**)malloc(numObjects * sizeof(float*));
        attributes[0] = (float*) malloc(numObjects * numAttributes * sizeof(float));
        for (i = 1; i < numObjects; i++)
            attributes[i] = attributes[i - 1] + numAttributes;
        rewind(infile);
        i = 0;
        while (fgets(line, 1024, infile) != NULL) {
            if (strtok(line, " \t\n") == NULL) continue;
            for (j = 0; j < numAttributes; j++) {
                buf[i] = atof(strtok(NULL, " ,\t\n"));
                i++;
            }
        }
        fclose(infile);
    }
    printf("I/O completed\n");

    memcpy(attributes[0], buf, numObjects * numAttributes * sizeof(float));

    cudaDeviceSynchronize();
    timing = 0.0;
    for (i = 0; i < nloops; i++) {
        cluster_centres = NULL;
        cluster(numObjects,
                numAttributes,
                attributes,
                nclusters,
                threshold,
                &cluster_centres);
    }
    cudaDeviceSynchronize();

    printf("number of Clusters %d\n", nclusters);
    printf("number of Attributes %d\n\n", numAttributes);

    printf("Time for process: %f\n", timing);

    free(attributes);
    free(cluster_centres[0]);
    free(cluster_centres);
    free(buf);
    return(0);
}
